class Trie {
    TrieNode root = new TrieNode();

    void insert(String word) {
        TrieNode cur = root;
        for (char c : word.toCharArray()) {
            cur.children.computeIfAbsent(c, k -> new TrieNode());
            cur = cur.children.get(c);
        }
        cur.isEnd = true;
    }

    boolean startsWith(String prefix) {
        TrieNode cur = root;
        for (char c : prefix.toCharArray()) {
            if (!cur.children.containsKey(c)) return false;
            cur = cur.children.get(c);
        }
        return true;
    }

    static class TrieNode {
        Map<Character, TrieNode> children = new HashMap<>();
        boolean isEnd;
    }
}

// Detect cycle AND find cycle start
ListNode detectCycle(ListNode head) {
    ListNode slow = head, fast = head;
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) {          // cycle detected
            slow = head;             // reset slow to head
            while (slow != fast) {  // both move 1 step
                slow = slow.next;
                fast = fast.next;
            }
            return slow;            // cycle start node
        }
    }
    return null; // no cycle
}

// Kruskal's MST
int minCostConnect(int n, int[][] edges) {
    Arrays.sort(edges, Comparator.comparingInt(e -> e[2]));
    UnionFind uf = new UnionFind(n);
    int cost = 0, count = 0;
    for (int[] edge : edges) {
        if (uf.union(edge[0], edge[1])) { // connects two components
            cost += edge[2];
            if (++count == n - 1) break; // MST complete
        }
    }
    return count == n - 1 ? cost : -1; // -1 if not fully connected
}

int lcs(String s1, String s2) {
    int m = s1.length(), n = s2.length();
    int[][] dp = new int[m+1][n+1];
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (s1.charAt(i-1) == s2.charAt(j-1))
                dp[i][j] = dp[i-1][j-1] + 1;
            else
                dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]);
        }
    }
    return dp[m][n];
}

boolean hasCycle(int n, List<List<Integer>> adj) {
    int[] color = new int[n]; // 0=white, 1=gray, 2=black
    for (int i = 0; i < n; i++)
        if (color[i] == 0 && dfs(i, adj, color)) return true;
    return false;
}
bool dfs(int u, List<List<Integer>> adj, int[] color) {
    color[u] = 1; // gray: in stack
    for (int v : adj.get(u)) {
        if (color[v] == 1) return true;   // back edge = cycle
        if (color[v] == 0 && dfs(v, adj, color)) return true;
    }
    color[u] = 2; // black: done
    return false;
}

