int lengthOfLIS(int[] nums) {
    List<Integer> tails = new ArrayList<>();
    for (int num : nums) {
        int lo = 0, hi = tails.size();
        while (lo < hi) {
            int mid = lo + (hi - lo) / 2;
            if (tails.get(mid) < num) lo = mid + 1;
            else                      hi = mid;
        }
        if (lo == tails.size()) tails.add(num);  // extend LIS
        else tails.set(lo, num);                  // replace for smaller tail
    }
    return tails.size();
}

// Fenwick Tree (BIT) — prefix sum query and point update
class BIT {
    int[] tree;
    BIT(int n) { tree = new int[n + 1]; }

    void update(int i, int delta) {
        for (; i < tree.length; i += i & (-i))
            tree[i] += delta;
    }

    int query(int i) { // prefix sum [1, i]
        int sum = 0;
        for (; i > 0; i -= i & (-i))
            sum += tree[i];
        return sum;
    }

    int range(int lo, int hi) { return query(hi) - query(lo - 1); }
}
